<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],   
            DataLoaded: 0,      
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: "Contract Name",
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                                onChange: this.CommonOnChange
                            },
                        },
                        {
                            astype: "MultiSelectField",
                            label: "Utility Name",
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: []
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: "Invoice Grouping",
                            name: "InvoiceGrouping",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: []
                            }
                        }
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "MultiSelectField",
                            label: "Cost Centers",
                            name: "CostCenter",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: []
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Invoice Date From(M/D/YYYY)'),
                            name: "InvoicedtFrom",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {
                                format: "M/D/YYYY",
                                options: [],
                                onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Invoice Date To(M/D/YYYY)'),
                            name: "InvoicedtTo",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {
                                format: "M/D/YYYY",
                                options: []
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: []
                            }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("Group By"),
                            name: "GroupBy",
                            value: "CostCenter",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [{ name: 'Cost Centers', value: 'CostCenter' }, { name: 'Contract', value: 'Customer' }, { name: 'Invoice Grouping', value: 'Invoice Grouping' }, { name: 'State', value: 'State' }, { name: 'Utility Name', value: 'UtilityName'}]                             
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetDDLStateList();
        await vm.GetCostCenters();  
    },
    methods: {
        setTimerDate:function(x, y, z){
            var vm =this;
            if(y.name == "InvoicedtFrom"){                           
                vm.$refs.BarcodeReport.updateProperty("InvoicedtTo", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            }                      
        },
        formatDate(value) {
            return moment(value).format('YYYY-MM-DD')
        },
        onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.reportPath = '';
            vm.parameter = [];
            let myObj = {
                reportName: "monthlyrevenuesummaryreport",
                ContractName: e.ContractName,
                UtilityName: e.UtilityName.length > 0 ? e.UtilityName.map(item => item.value).join(",") : '',
                InvoiceGrouping: e.InvoiceGrouping.length > 0 ? e.InvoiceGrouping.map(item => item.value).join(",") : '',
                CostCenter: e.CostCenter.length > 0 ? e.CostCenter.map(item => item.value).join(",") : '',
                InvoicedtFrom: e.InvoicedtFrom ? vm.formatDate(e.InvoicedtFrom) : null,
                InvoicedtTo: e.InvoicedtTo ? vm.formatDate(e.InvoicedtTo) : null,
                State: e.State.length > 0 ? e.State.map(item => item.value).join(",") : '',
                GroupBy: e.GroupBy
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            })
            vm.isLoading = false;
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options=[];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[3].value = '';
            (vm.FormSchema)[1].Data[4].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.$refs.BarcodeReport.validateForm.reset();  
        },
        CommonOnChange(x, y, z){
            var vm = this;
            vm.ClientIds = y.value;
            if (vm.ClientIds && vm.ClientIds > 0) {
                vm.GetUtilityByClient();   
                vm.GetDivisionListByCilentId();  
            }
        },
        GetClient: async function () {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom="CUSTOM"&search=null&userId=null';
            DataServices.GetClient(params).then((response) => {
                if (response.data.length > 0) {
                    var ClientData = response.data;
                    ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUtilityByClient: async function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options=[];
            vm.FormSchema[0].Data[1].value = ''; 
            if (vm.ClientIds > 0) {
                var url = `clientId=${vm.ClientIds}&configid=0&Reqfrom=&clientIds=`;
                await DataServices.GetUtilityByClient(url).then((response) => {
                    if (response.data.length > 0) {
                        var UtilityData = response.data;
                        UtilityData.forEach(element => {
                            var Obj = {
                                name: element.UTILITY_NAME,
                                value: element.UTILITY_ID
                            }
                            vm.FormSchema[0].Data[1].config.options.push(Obj);
                        });
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }).catch((error) => {
                    console.error("Error fetching utilities:", error);
                });
            } else {
                console.warn("No valid ClientIds to fetch utility data.");
            }
        },
        GetDivisionListByCilentId: async function () {
            var vm = this;
            if (vm.ClientIds > 0) {
                var url = `clientId=${vm.ClientIds}`;
                await DataServices.GetDivisionListByCilentId(url).then((response) => {
                    if (response.data.length > 0) {
                        var DivisionData = response.data;
                        DivisionData.forEach(element => {
                            var Obj = {
                                name: element.NAME,
                                value: element.DIVISIONS_ID
                            }
                            vm.FormSchema[0].Data[2].config.options.push(Obj);
                        });
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }).catch((error) => {
                    console.error("Error fetching divisions:", error);
                });
            } else {
                console.warn("No valid ClientIds to fetch division list.");
            }
        },
        GetCostCenters: async function () {
            var vm = this;
            await DataServices.GetCostCenters().then((response) => {
                if (response.data != '') {
                    var CostCentresData = response.data;
                    CostCentresData.forEach(item => {
                        vm.FormSchema[1].Data[0].config.options.push({
                            name: item.text,
                            value: item.value
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        GetDDLStateList: async function () {
            var vm = this;
            var params = `CountryId=223&InclueCandaState=true`;
            DataServices.GetDDLStateList(params).then((response) => {
                if (response.data.length > 0) {
                    var StateData = response.data;
                    StateData.forEach(item => {
                        vm.FormSchema[1].Data[3].config.options.push({
                            name: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            value: item.STATE_ID
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        }
    }
}
</script>
