<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import moment from 'moment';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,        
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "textField",
                            label: this.$t("INVOICE NUMBER"),
                            name: "INVOICENUMBER",
                            value: "",
                            placeholder: "INVOICE NUMBER"
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Issue Date From (M/D/YYYY)'),
                            name: "IssuedtFrom",
                            value: "",
                            placeholder: this.$t('(M/D/YYYY)'),
                            config: {
                                format: "M/D/YYYY",
                                 onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Issue Date To (M/D/YYYY)'),
                            name: "IssuedtTO",
                            value: "",
                            placeholder: this.$t('(M/D/YYYY)'),
                            config: {
                                format: "M/D/YYYY",
                            }
                        }
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "textField",
                            label: this.$t("Amount Range"),
                            name: "AmountRangeFrom",
                            value: "",
                            placeholder: "From"
                        },
                        {
                            astype: "textField",
                            label: '',
                            name: "AmountRangeTo",
                            value: "",
                            placeholder: 'To',

                        },
                        {
                            astype: "DateField",
                            label: this.$t('Due Date From (M/D/YYYY)'),
                            name: "DuedtFrom",
                            value: "",
                            placeholder: this.$t('(M/D/YYYY)'),
                            config: {
                                 format: "M/D/YYYY",
                                 onChange: this.setTimerDate,

                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Due Date To (M/D/YYYY)'),
                            name: "DuedtTO",
                            value: "",
                            placeholder: this.$t('(M/D/YYYY)'),
                            config: {
                                format: "M/D/YYYY",
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "DateField",
                            label: this.$t('Payment Date From (M/D/YYYY)'),
                            name: "PaymentdtFrom",
                            value: "",
                            placeholder: this.$t('(M/D/YYYY)'),
                            config: {
                                format: "M/D/YYYY",
                                onChange: this.setTimerDate,
                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Payment Date To (M/D/YYYY)'),
                            name: "PaymentdtTO",
                            value: "",
                            placeholder: this.$t('(M/D/YYYY)'),
                            config: {
                                format: "M/D/YYYY",
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Invoice Status"),
                            name: "InvoiceStatus",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('InvoiceStatus'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetStatusList();
    },
    methods: {
         setTimerDate:function(x, y, z){
            var vm =this;
            if(y.name == "IssuedtFrom"){                           
                vm.$refs.BarcodeReport.updateProperty("IssuedtTO", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            } 
            if(y.name == "DuedtFrom"){                           
                vm.$refs.BarcodeReport.updateProperty("DuedtTO", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            } 
            if(y.name == "PaymentdtFrom"){                           
                vm.$refs.BarcodeReport.updateProperty("PaymentdtTO", "config.minDate", x);
                vm.$refs.BarcodeReport.UpdateKeyValue();                      
            }  
        },
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = ''; 
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[1].value = '';
            (vm.FormSchema)[2].Data[2].value = '';        
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[3].value = '';
            vm.reportPath = '';
            vm.parameter = [];
            vm.$refs.BarcodeReport.validateForm.reset();
        },
         formatDate(value) {
            return moment(value).format('MM-DD-YYYY')
        },
        onSubmit(e) {
            var reportviewerObj = $("#viewer").data("boldReportViewer");
            if (reportviewerObj != null) {
                reportviewerObj.destroy();
            }
            var vm = this;
            vm.isLoading = true;
            vm.reportPath = '';
            vm.parameter = [];
            let myObj = {
                reportName: "invoicedetailreport",
                invoiceNumber: e.INVOICENUMBER,
                billIssueDateFrom: e.IssuedtFrom ? vm.formatDate(e.IssuedtFrom) : null,
                billIssueDateTo: e.IssuedtTO ? vm.formatDate(e.IssuedtTO) : null,  
                AmountFrom:e.AmountRangeFrom, 
                AmountTo: e.AmountRangeTo,
                billDueDateFrom:e.DuedtFrom ? vm.formatDate(e.DuedtFrom) : null, 
                billDueDateTo:e.DuedtTO ? vm.formatDate(e.DuedtTO) : null, 
                billpaymentDateFrom: e.PaymentdtFrom ? vm.formatDate(e.PaymentdtFrom) : null,
                billpaymentTo: e.PaymentdtTO,
                StatusIds: e.InvoiceStatus.length > 0 ? e.InvoiceStatus.map(item => item.value).join(",") : '',
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.ReportPath;
                vm.parameter = response.data.parameters;
            })
            vm.isLoading = false;
        },
        GetStatusList: async function () {
            var vm = this;
            var url = `langCode=en&statusType=ClientBilling&hasglobal=false`
            await DataServices.GetStatusList(url).then((response) => {
                if (response.data.length > 0) {
                    var LocationData = response.data;
                    LocationData.forEach(element => {
                        var Obj = {
                            name: element.STATUS,
                            value: element.STATUS_ID
                        }
                        vm.FormSchema[2].Data[2].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        }
    }
};
</script>
