<template>
    <div class="padding-t_10" id="reportstabsdata">
        <div class="left-menu-tab new_tab">
            <div class="col-md-12 p-0">
                <div class="theme-primary partition">
                    <span class="p-name text-white">{{ $t("InvoiceReport") }}</span>
                </div>
            </div>
            <div class="left-tab-container">
                <div class="pt-2 mb-1 w-100 d-none d-lg-block">
                    <div class="input-group customsearchbox">
                        <input 
                            type="text" 
                            maxlength="50" 
                            :placeholder="Search" 
                            class="form-control searchcustomfilter border-right-0" 
                            autocomplete="off" 
                            v-model="searchQuery" 
                        />
                        <div class="input-group-append">
                            <span class="input-group-text bg-transparent bg-white border-left-0">
                                <i class="fa fa-search"></i>
                            </span>
                        </div>
                    </div>
                </div>
                <div class="mt-2" id="divscrollsetuptabs" style="max-height: 700px">
                    <ul class="nav nav-pills flex-column left-tab responivecustomtab lefttabiconfix lefttabflexible" id="upper" role="tablist">
                        <li v-for="(tab, index) in filteredTabs" :key="index">
                            <a 
                                class="nav-link left-menu" 
                                :data-toggle="'#' + tab.id" 
                                :class="{ active: activeKey === tab.index }" 
                                @click="activateTab(tab.index)"
                            >
                                <i :class="tab.icon" aria-hidden="true"></i>
                                {{ $t(tab.name) }}
                            </a>
                        </li>
                    </ul>
                </div>
            </div>
        </div>
        
        <div class="right-content">
            <loader :isVisible="isLoading"></loader>
            <div class="col-md-12 p-0">
                <div class="theme-primary partition" style="overflow: visible">
                    <span class="p-name text-white" id="spnreporttext">{{ this.$t(activeTabName) }}</span>
                </div>
            </div>
            <div class="col-md-12 p-0">
                <div class="tab-content" id="myTabContent">
                    <component 
                        v-for="(tab, index) in tabNames" 
                        :key="index" 
                        :is="getComponent(tab)" 
                        class="tab-pane" 
                        :class="{ 'active show': activeKey == index }" 
                        v-if="activeKey == index"
                    ></component>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';

import MTDReport from "../InvoiceReport/MTDReport.vue";
import AccountDetailReport from "../InvoiceReport/AccountDetailReport.vue";
import AuditRecordsReport from "../InvoiceReport/AuditRecordsReport.vue";
import BilledUnbilledReport from "../InvoiceReport/BilledUnbilledReport.vue";
import BilledUnbilledSummaryReport from "../InvoiceReport/BilledUnbilledSummaryReport.vue";
import BillingRuleReport from "../InvoiceReport/BillingRuleReport.vue";
import BillingRueMissingReports from "../InvoiceReport/BillingRueMissingReports.vue";
import BillingServiceListReport from "../InvoiceReport/BillingServiceListReport.vue";
import BillingServiceReport from "../InvoiceReport/BillingServiceReport.vue";
import ContractDetailReport from "../InvoiceReport/ContractDetailReport.vue";
import FlagDetailReport from "../InvoiceReport/FlagDetailReport.vue";
import FlagSummaryReport from "../InvoiceReport/FlagSummaryReport.vue";
import InvoiceDetailReport from "../InvoiceReport/InvoiceDetailReport.vue";
import InvoiceSummaryByWork from "../InvoiceReport/InvoiceSummaryByWork.vue";
import InvoiceSummary from "../InvoiceReport/InvoiceSummaryReport.vue";
import Milestone from "../InvoiceReport/MileStoneReport.vue";
import MissingRatesInWorkcode from "../InvoiceReport/MissingRatesInWorkcode.vue";
import MissingRatesInActivities from "../InvoiceReport/MissingRatesInActivity.vue";
import MissingSetupReport from "../InvoiceReport/MissingSetupReport.vue";
import MonthlyRevenueDetailReport from "../InvoiceReport/MonthlyRevenueDetailReport.vue";
import MonthlyRevenueSummaryReport from "../InvoiceReport/MonthlyRevenueSummaryReport.vue";
import NotesReport from "../InvoiceReport/NotesReport.vue";
import ProcessedUnProccesedReport from "../InvoiceReport/ProcessedUnprocessedReport.vue";
import RevenueByCustomerReport from "../InvoiceReport/RevenueByCustomerReport.vue";
import SuppressedCodeReport from '../InvoiceReport/SuppressedCodeReport.vue';
import TicketAuditLogReport from '../InvoiceReport/TicketAuditLogReport.vue';
import PreviewInvoice from '../InvoiceReport/PreviewInvoice.vue';
import DataServices from "../../services/DataService";

export default {
    components: {
        AccountDetailReport,
        AuditRecordsReport,
        BilledUnbilledReport,
        BilledUnbilledSummaryReport,
        BillingRuleReport,
        BillingRueMissingReports,
        BillingServiceListReport,
        BillingServiceReport,
        ContractDetailReport,
        FlagDetailReport,
        FlagSummaryReport,
        InvoiceDetailReport,
        InvoiceSummaryByWork,
        InvoiceSummary,
        Milestone,
        MissingRatesInWorkcode,
        MissingRatesInActivities,
        MissingSetupReport,
        MonthlyRevenueDetailReport,
        MonthlyRevenueSummaryReport,
        MTDReport,
        NotesReport,
        ProcessedUnProccesedReport,
        RevenueByCustomerReport,
        SuppressedCodeReport,
        TicketAuditLogReport,
        PreviewInvoice
    },
    
    data() {
        return {
            activeKey: 0,
            tabNames: [
                // "Account Detail Report",
                // "Audit Records Report",
                // "Billed/Unbilled Report",
                // "Billed/Unbilled Summary Report",
                // "Billing Rule Report",
                // "Billing Rules Missing Limits Report",
                // "Billing Service List Report",
                // "Billing Service Report",
                // "Contract Detail Report",
                // "Flag Detail Report",
                // "Flag Summary Report",
                // "Payment Status Report",
                 "Invoice Details Report",
                // "Invoice Summary Report",
                 "Milestone Report",
                // "Missing Rates In Activities Report",
                // "Missing Rates In WorkCode Report",
                // "Missing Setup Report",
                // "Monthly Revenue Detail Report",
                // "Monthly Revenue Summary Report",
                // "MTD Report",
                 "Notes Report",
                // "Processed/Unprocessed Report",
                // "Revenue By Customer and District Date Report",
                // "Suppressed Code Report",
                // "Ticket Audit Log Report",
                //"Preview Invoice"
            ],
            IsUsicval: "",
            IsCheck: "",
            searchQuery: "",
            Isrevenue: "",
            NotesVal: "",
            UserLicenseModules: []
        };
    },
    
    mounted() {
        this.activateTab(0);
    },
    
    computed: {
        filteredTabs() {
            if (!this.searchQuery) {
                return this.tabNames.map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }));
            }
            
            const query = this.searchQuery.toLowerCase();
            const filtered = this.tabNames
                .map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }))
                .filter(tab => this.$t(tab.name).toLowerCase().includes(query));
                
            if (query.trim() !== '' && filtered.length === 0) {
                return [{
                    name: 'No tabs found for "' + this.searchQuery + '"',
                    index: -1,
                    icon: 'no-icon'
                }];
            }
            
            return filtered;
        },
        
        activeTabName() {
            return this.tabNames[this.activeKey];
        }
    },
    
    created: async function() {
        var vm = this;
        await vm.GetNotes();
        await vm.IsUsic();
        await vm.GetUserLicenseModulesReport();
        await vm.setTabNames();
    },
    
    methods: {
        setTabNames: async function() {
            var vm = this;

            const has = (action) =>
                vm.UserLicenseModules.filter(
                    x => x.controllerName.toUpperCase() === 'INVOICEREPORT' &&
                    x.actionName.toUpperCase() === action
                ).length > 0;

            const addTab = (title) => {
                if (!vm.tabNames.includes(title)) {
                    vm.tabNames.push(title);
                }
            };

            if (has('INVOICEDETAILREPORT')) {
                addTab("Payment Status Report");
            }

            if (vm.IsCheck && has('MTDREPORT')) {
                addTab("MTD Report");
            }

            if (has('MILESTONEREPORT')) {
                addTab("Milestone Report");
            }

            if (vm.IsUsicval) {
                if (has('HISTORICALDETAILEDDATAREPORT')) {
                    addTab("Billed/Unbilled Report");
                }

                if (has('HISTORICALDETAILEDDATASUMMARYREPORT')) {
                    addTab("Billed/Unbilled Summary Report");
                }

                if (vm.GetUserInfo.UserType == "CA" || vm.GetUserInfo.UserType == "PM") {
                    if (has('FLAGSUMMARYREPORT')) addTab("Flag Summary Report");
                    if (has('FLAGDETAILREPORT')) addTab("Flag Detail Report");
                }

                if (has('MONTHLYREVENUEDETAILREPORT')) addTab("Monthly Revenue Detail Report");
                if (has('MONTHLYREVENUESUMMARYREPORT')) addTab("Monthly Revenue Summary Report");
                if (has('ACCOUNTDETAILREPORT')) addTab("Account Detail Report");
                if (has('SUPPRESSEDCODEREPORT')) addTab("Suppressed Code Report");
                if (has('AUDITRECORDSREPORT')) addTab("Audit Records Report");
                if (has('CONTRACTDETAILREPORT')) addTab("Contract Detail Report");
                if (has('BILLINGSERVICELISTREPORT')) addTab("Billing Service List Report");
                if (has('TICKETAUDITLOGREPORT')) addTab("Ticket Audit Log Report");
                if (has('PROCESSEDUNPROCESSEDREPORT')) addTab("Processed/Unprocessed Report");
                if (has('REVENUEBYCUSTOMERDISTRICTDATEREPORTNONGROUPED')) addTab("Revenue By Customer and District Date Report");

                if (vm.Isrevenue && has('REVENUECOMPARISONREPORT')) addTab("Invoice Summary Report");

                if (has('MISSINGSETUPREPORT')) addTab("Missing Setup Report");
                if (has('BILLINGRULESMISSINGLIMITSREPORT')) addTab("Billing Rules Missing Limits Report");
                if (has('MISSINGRATESREPORT')) addTab("Missing Rates In Activities Report");
                if (has('MISSINGRATESINWORKCODEREPORT')) addTab("Missing Rates In WorkCode Report");
                if (has('INVOICESUMMARYBYWORKCODECOSTCENTERREPORT')) addTab("Invoice Summary Report");

                if (vm.NotesVal === "yes") addTab("Notes Report");

                addTab("Billing Service Report");
                addTab("Billing Rule Report");
                addTab("Preview Invoice");

                vm.tabNames.sort();
            }
        },
        
        GetUserLicenseModulesReport: async function() {
            var vm = this;
            vm.isLoading = true;
            await DataServices.GetUserLicenseModulesReport().then(response => {
                vm.isLoading = false;
                vm.UserLicenseModules = response.data.list;
            });
        },
        
        IsUsic: async function() {
            var vm = this;
            var url = `featureCode=USICBILLING`;
            var parm = `featureCode=CBILLR`;
            var parms = `featureCode=RevenueComparisonReport`;
            
            await DataServices.CheckExtraFeatures(url).then((response) => {
                if (response.data != null) {
                    this.IsUsicval = response.data;
                }
            });
            
            await DataServices.CheckExtraFeatures(parm).then((response) => {
                if (response.data != null) {
                    this.IsCheck = response.data;
                }
            });
            
            await DataServices.CheckExtraFeatures(parms).then((response) => {
                if (response.data != null) {
                    this.Isrevenue = response.data;
                }
            });
        },
        
        GetNotes: async function() {
            var vm = this;
            var url = `configkey=EnableNotes`;
            await DataServices.GetNotesByCompanyId(url).then((response) => {
                if (response.data != null) {
                    this.NotesVal = response.data;
                }
            });
        },
        
        getTabIcon(name) {
            switch (name) {
                case "Account Detail Report":
                    return "fa fa-columns";
                case "Audit Records Report":
                    return "fa fa-list";
                case "Billed/Unbilled Report":
                    return "fa fa-money";
                case "Billed/Unbilled Summary Report":
                    return "fa fa-list-ul";
                case "Billing Rule Report":
                    return "fa fa-align-justify";
                case "Billing Rules Missing Limits Report":
                    return "fa fa-bar-chart";
                case "Billing Service List Report":
                    return "fa fa-align-justify";
                case "Billing Service Report":
                    return "fa fa-align-justify";
                case "Contract Detail Report":
                    return "fa fa-file-text";
                case "Flag Detail Report":
                    return "fa fa-flag-o";
                case "Flag Summary Report":
                    return "fa fa-flag";
                case "Payment Status Report":
                    return "fa fa-list-alt";
                case "Invoice Details Report":
                    return "fa fa-file";
                case "Invoice Summary Report":
                    return "fa fa-print";
                case "Milestone Report":
                    return "fa fa-map-signs";
                case "Missing Rates In WorkCode Report":
                    return "fa fa-money";
                case "Missing Rates In Activities Report":
                    return "fa fa-ban";
                case "Missing Setup Report":
                    return "fa fa-cog";
                case "Monthly Revenue Detail Report":
                    return "fa fa-calendar-o";
                case "Monthly Revenue Summary Report":
                    return "fa fa-calendar";
                case "MTD Report":
                    return "fa fa-calculator";
                case "Notes Report":
                    return "fa fa-align-justify";
                case "Processed/Unprocessed Report":
                    return "fa fa-file-o";
                case "Revenue By Customer and District Date Report":
                    return "fa fa-user-circle";
                case "Suppressed Code Report":
                    return "fa fa-file-code-o";
                case "Ticket Audit Log Report":
                    return "fa fa-file-text";
                case "Preview Invoice":
                    return "fa fa-eye";
                default:
                    return "";
            }
        },
        
        getComponent(tabName) {
            switch (tabName) {
                case "Account Detail Report":
                    return "AccountDetailReport";
                case "Audit Records Report":
                    return "AuditRecordsReport";
                case "Billed/Unbilled Report":
                    return "BilledUnbilledReport";
                case "Billed/Unbilled Summary Report":
                    return "BilledUnbilledSummaryReport";
                case "Billing Rule Report":
                    return "BillingRuleReport";
                case "Billing Rules Missing Limits Report":
                    return "BillingRueMissingReports";
                case "Billing Service List Report":
                    return "BillingServiceListReport";
                case "Billing Service Report":
                    return "BillingServiceReport";
                case "Contract Detail Report":
                    return "ContractDetailReport";
                case "Flag Detail Report":
                    return "FlagDetailReport";
                case "Flag Summary Report":
                    return "FlagSummaryReport";
                case "Payment Status Report":
                    return "InvoiceDetailReport";
                case "Invoice Details Report":
                    return "InvoiceSummaryByWork";
                case "Invoice Summary Report":
                    return "InvoiceSummary";
                case "Milestone Report":
                    return "Milestone";
                case "Missing Rates In WorkCode Report":
                    return "MissingRatesInWorkcode";
                case "Missing Rates In Activities Report":
                    return "MissingRatesInActivities";
                case "Missing Setup Report":
                    return "MissingSetupReport";
                case "Monthly Revenue Detail Report":
                    return "MonthlyRevenueDetailReport";
                case "Monthly Revenue Summary Report":
                    return "MonthlyRevenueSummaryReport";
                case "MTD Report":
                    return "MTDReport";
                case "Notes Report":
                    return "NotesReport";
                case "Processed/Unprocessed Report":
                    return "ProcessedUnProccesedReport";
                case "Revenue By Customer and District Date Report":
                    return "RevenueByCustomerReport";
                case "Suppressed Code Report":
                    return "SuppressedCodeReport";
                case "Ticket Audit Log Report":
                    return "TicketAuditLogReport";
                case "Preview Invoice":
                    return "PreviewInvoice";
                default:
                    return null;
            }
        },
        
        activateTab(index) {
            this.activeKey = index;
        }
    }
};
</script>

<style scoped>
.left-tab-container {
    max-height: 70vh;
    overflow-y: auto;
}

.left-tab .nav-link.left-menu a {
    width: 100%;
    display: flex;
}

.left-tab .nav-link.left-menu:hover,
.listing:hover {
    color: #fff;
}

.left-tab .nav-link.left-menu.active .listing {
    color: #fff;
}
</style>